{
    topWall
    {
        type            fixedFluxPressure;
        value           uniform 1e5;
    }

    bottomWall
    {
        type            fixedFluxPressure;
        value           uniform 1e5;
    }

    leftWall
    {
        type            fixedFluxPressure;
        value           uniform 1e5;
    }

    rightWall
    {
        type            fixedFluxPressure;
        value           uniform 1e5;
